class BankAccount {
    double balance;
public:
    BankAccount(double b) : balance(b) {}
    bool withdraw(double amount) {
        if (amount <= balance) {
            balance -= amount;
            return true;
        }
        return false;
    }
    double getBalance() { return balance; }
};

int main() {
    BankAccount acc(1000);
    acc.withdraw(300);
    cout << acc.getBalance();
    return 0;
}

