class String {
    char* str;
    int len;
public:
    String(const char* s) {
        len = 0;
        while (s[len]) len++;
        str = new char[len + 1];
        for (int i = 0; i <= len; i++) str[i] = s[i];
    }
    int length() { return len; }
    ~String() { delete[] str; }
};

int main() {
    String s("Hello");
    cout << s.length();
    return 0;
}

