#include <iostream>
using namespace std;

class Handle {
    int id;
public:
    Handle(int i) : id(i) { cout << "C" << id; }
    Handle(Handle&& other) noexcept : id(other.id) {
        other.id = 0;
        cout << "M" << id;
    }
    ~Handle() { cout << "D" << id; }
};

int main() {
    Handle h1(1);
    Handle h2 = move(h1);
