#include <iostream>
#include <coroutine>
using namespace std;

struct Generator {
    struct promise_type {
        int current_value;
        suspend_always yield_value(int value) {
            current_value = value;
            return {};
        }
        suspend_always initial_suspend() { return {}; }
        suspend_always final_suspend() noexcept { return {}; }
        Generator get_return_object() { return Generator{this}; }
        void unhandled_exception() {}
        void return_void() {}
    };
    promise_type* promise;
    int next() {
        coroutine_handle<promise_type>::from_promise(*promise).resume();
        return promise->current_value;
    }
};

Generator count() {
    co_yield 1;
    co_yield 2;
}

int main() {
    auto gen = count();
    cout << gen.next();
    return 0;
}

