#include <iostream>
using namespace std;

template<typename T>
class ObjectPool {
    struct Node { T data; Node* next; };
    Node* freeList = nullptr;
public:
    T* acquire() {
        if (freeList) {
            Node* n = freeList;
            freeList = freeList->next;
            return &n->data;
        }
        return &(new Node)->data;
    }
    void release(T* p) {
        Node* n = reinterpret_cast<Node*>(p);
        n->next = freeList;
        freeList = n;
    }
};

int main() {
    ObjectPool<int> pool;
    int* a = pool.acquire();
    *a = 99;
    cout << *a;
    pool.release(a);
    return 0;
}

