template<typename T>
class Pool {
    vector<unique_ptr<T>> objects;
    vector<T*> available;
public:
    T* acquire() {
        if (available.empty()) {
            objects.push_back(make_unique<T>());
            return objects.back().get();
        }
        T* obj = available.back();
        available.pop_back();
        return obj;
    }
    void release(T* obj) {
        available.push_back(obj);
    }
    size_t poolSize() { return objects.size(); }
};

struct Resource { int id = 0; };

int main() {
    Pool<Resource> pool;
    auto* r1 = pool.acquire();
    auto* r2 = pool.acquire();
    pool.release(r1);
