template<typename T>
class LRUCache {
    size_t capacity;
    list<pair<int, T>> items;
    unordered_map<int, typename list<pair<int, T>>::iterator> cache;
public:
    LRUCache(size_t cap) : capacity(cap) {}
    void put(int key, T value) {
        if (cache.count(key)) {
            items.erase(cache[key]);
        } else if (items.size() == capacity) {
            cache.erase(items.back().first);
            items.pop_back();
        }
        items.push_front({key, value});
        cache[key] = items.begin();
    }
    size_t size() { return items.size(); }
};

int main() {
    LRUCache<string> cache(2);
    cache.put(1, "a");
    cache.put(2, "b");
    cache.put(3, "c");
    cout << cache.size();
    return 0;
}

