template<typename T>
class CircularBuffer {
    vector<T> buffer;
    size_t head = 0, tail = 0, count = 0;
public:
    CircularBuffer(size_t size) : buffer(size) {}
    void push(T val) {
        buffer[tail] = val;
        tail = (tail + 1) % buffer.size();
        if (count < buffer.size()) count++;
        else head = (head + 1) % buffer.size();
    }
    size_t size() { return count; }
};

