public:
    Lens(function<T(const T&)> g, function<T(T&, const T&)> s)
        : getter(g), setter(s) {}
    T get(const T& obj) const { return getter(obj); }
    void set(T& obj, const T& value) const { setter(obj, value); }
};

int main() {
    int x = 10;
    Lens<int> lens(
        [](const int& v) { return v; },
        [](int& v, const int& newVal) { v = newVal; return v; }
    );
    lens.set(x, 20);
    cout << lens.get(x);
    return 0;
}

