class Queue {
    vector<int> items;
public:
    void enqueue(int item) { items.push_back(item); }
    int dequeue() {
        if (items.empty()) throw runtime_error("Empty");
        int front = items.front();
        items.erase(items.begin());
        return front;
    }
    bool empty() const { return items.empty(); }
};

int main() {
    Queue q;
    q.enqueue(1); q.enqueue(2); q.enqueue(3);
    cout << q.dequeue();
    return 0;
}

